import React, { useState, useCallback } from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Button,
    Slider,
    Typography,
    Box,
    IconButton,
    Tooltip,
    CircularProgress,
} from '@mui/material';
import {
    Rotate90DegreesCcw as RotateIcon,
    Crop as CropIcon,
    Brightness6 as BrightnessIcon,
    Contrast as ContrastIcon,
    ColorLens as FilterIcon,
    Save as SaveIcon,
    Tune as TuneIcon,
    BlurOn as BlurIcon,
    Opacity as OpacityIcon,
} from '@mui/icons-material';
import Cropper from 'react-easy-crop';
import { motion } from 'framer-motion';
import { createCanvas, Image } from 'canvas';

const filters = {
    none: { name: 'Original', filter: 'none' },
    grayscale: { name: 'Black & White', filter: 'grayscale(100%)' },
    sepia: { name: 'Sepia', filter: 'sepia(100%)' },
    warm: { name: 'Warm', filter: 'saturate(150%) hue-rotate(30deg)' },
    cool: { name: 'Cool', filter: 'saturate(150%) hue-rotate(-30deg)' },
    vintage: { name: 'Vintage', filter: 'sepia(50%) hue-rotate(-30deg) saturate(120%)' },
    fade: { name: 'Fade', filter: 'opacity(85%) hue-rotate(20deg)' },
    dramatic: { name: 'Dramatic', filter: 'contrast(120%) saturate(110%)' }
};

const ImageEditor = ({ open, onClose, image, onSave }) => {
    const [crop, setCrop] = useState({ x: 0, y: 0 });
    const [zoom, setZoom] = useState(1);
    const [rotation, setRotation] = useState(0);
    const [brightness, setBrightness] = useState(100);
    const [contrast, setContrast] = useState(100);
    const [saturation, setSaturation] = useState(100);
    const [blur, setBlur] = useState(0);
    const [opacity, setOpacity] = useState(100);
    const [currentFilter, setCurrentFilter] = useState('none');
    const [croppedAreaPixels, setCroppedAreaPixels] = useState(null);
    const [imageUrl, setImageUrl] = useState(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [previewCanvas, setPreviewCanvas] = useState(null);

    // Создаем URL для изображения при монтировании компонента
    React.useEffect(() => {
        if (image) {
            const url = URL.createObjectURL(image);
            setImageUrl(url);
            return () => URL.revokeObjectURL(url);
        }
    }, [image]);

    // Обновляем предпросмотр при изменении параметров
    React.useEffect(() => {
        if (imageUrl && croppedAreaPixels) {
            updatePreview();
        }
    }, [brightness, contrast, saturation, blur, opacity, currentFilter]);

    const updatePreview = useCallback(async () => {
        if (!imageUrl || !croppedAreaPixels) return;

        try {
            const canvas = createCanvas(croppedAreaPixels.width, croppedAreaPixels.height);
            const ctx = canvas.getContext('2d');
            const img = new Image();

            await new Promise((resolve, reject) => {
                img.onload = resolve;
                img.onerror = reject;
                img.src = imageUrl;
            });

            // Применяем трансформации
            ctx.save();
            ctx.translate(canvas.width/2, canvas.height/2);
            ctx.rotate((rotation * Math.PI) / 180);
            ctx.translate(-canvas.width/2, -canvas.height/2);

            // Рисуем изображение
            ctx.drawImage(
                img,
                croppedAreaPixels.x,
                croppedAreaPixels.y,
                croppedAreaPixels.width,
                croppedAreaPixels.height,
                0,
                0,
                croppedAreaPixels.width,
                croppedAreaPixels.height
            );

            ctx.restore();

            // Применяем фильтры и эффекты
            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
            const data = imageData.data;

            for (let i = 0; i < data.length; i += 4) {
                // Яркость
                const brightnessFilter = (brightness - 100) / 100;
                data[i] += 255 * brightnessFilter;
                data[i + 1] += 255 * brightnessFilter;
                data[i + 2] += 255 * brightnessFilter;

                // Контраст
                const contrastFilter = (contrast - 100) / 100;
                data[i] += (data[i] - 128) * contrastFilter;
                data[i + 1] += (data[i + 1] - 128) * contrastFilter;
                data[i + 2] += (data[i + 2] - 128) * contrastFilter;

                // Насыщенность
                const saturationFilter = saturation / 100;
                const gray = 0.2989 * data[i] + 0.5870 * data[i + 1] + 0.1140 * data[i + 2];
                data[i] = gray + (data[i] - gray) * saturationFilter;
                data[i + 1] = gray + (data[i + 1] - gray) * saturationFilter;
                data[i + 2] = gray + (data[i + 2] - gray) * saturationFilter;

                // Прозрачность
                data[i + 3] = data[i + 3] * (opacity / 100);
            }

            ctx.putImageData(imageData, 0, 0);

            // Применяем размытие если нужно
            if (blur > 0) {
                const blurPass = (srcData, width, height, radius) => {
                    const dst = new Uint8ClampedArray(srcData.length);
                    const size = radius * 2 + 1;
                    const divisor = size * size;

                    for (let i = 0; i < height; i++) {
                        for (let j = 0; j < width; j++) {
                            let r = 0, g = 0, b = 0, a = 0;
                            for (let y = -radius; y <= radius; y++) {
                                const yi = Math.min(Math.max(i + y, 0), height - 1);
                                for (let x = -radius; x <= radius; x++) {
                                    const xi = Math.min(Math.max(j + x, 0), width - 1);
                                    const idx = (yi * width + xi) * 4;
                                    r += srcData[idx];
                                    g += srcData[idx + 1];
                                    b += srcData[idx + 2];
                                    a += srcData[idx + 3];
                                }
                            }
                            const idx = (i * width + j) * 4;
                            dst[idx] = r / divisor;
                            dst[idx + 1] = g / divisor;
                            dst[idx + 2] = b / divisor;
                            dst[idx + 3] = a / divisor;
                        }
                    }
                    return dst;
                };

                const blurRadius = Math.floor(blur / 10);
                if (blurRadius > 0) {
                    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
                    const blurred = blurPass(imageData.data, canvas.width, canvas.height, blurRadius);
                    imageData.data.set(blurred);
                    ctx.putImageData(imageData, 0, 0);
                }
            }

            setPreviewCanvas(canvas);
        } catch (error) {
            console.error('Error updating preview:', error);
        }
    }, [imageUrl, croppedAreaPixels, rotation, brightness, contrast, saturation, blur, opacity, currentFilter]);

    const onCropComplete = useCallback((croppedArea, croppedAreaPixels) => {
        setCroppedAreaPixels(croppedAreaPixels);
    }, []);

    const handleSave = useCallback(async () => {
        if (!previewCanvas) return;
        setIsProcessing(true);
        try {
            const blob = await new Promise(resolve => previewCanvas.toBlob(resolve, 'image/jpeg', 0.95));
            onSave(blob);
            onClose();
        } catch (error) {
            console.error('Error saving image:', error);
        } finally {
            setIsProcessing(false);
        }
    }, [previewCanvas, onSave, onClose]);

    if (!image) return null;

    return (
        <Dialog
            open={open}
            onClose={onClose}
            maxWidth="md"
            fullWidth
            PaperComponent={motion.div}
            PaperProps={{
                initial: { scale: 0.9, opacity: 0 },
                animate: { scale: 1, opacity: 1 },
                transition: { duration: 0.2 }
            }}
        >
            <DialogTitle>Редактировать изображение</DialogTitle>
            <DialogContent>
                <Box sx={{ position: 'relative', height: 400, mb: 2 }}>
                    {imageUrl && (
                        <Cropper
                            image={imageUrl}
                            crop={crop}
                            zoom={zoom}
                            rotation={rotation}
                            aspect={4/3}
                            onCropChange={setCrop}
                            onZoomChange={setZoom}
                            onCropComplete={onCropComplete}
                        />
                    )}
                </Box>

                <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
                    <Tooltip title="Повернуть">
                        <IconButton onClick={() => setRotation((r) => (r + 90) % 360)}>
                            <RotateIcon />
                        </IconButton>
                    </Tooltip>
                    <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="caption">Яркость</Typography>
                        <Slider
                            value={brightness}
                            onChange={(_, value) => setBrightness(value)}
                            min={0}
                            max={200}
                        />
                    </Box>
                    <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="caption">Контраст</Typography>
                        <Slider
                            value={contrast}
                            onChange={(_, value) => setContrast(value)}
                            min={0}
                            max={200}
                        />
                    </Box>
                </Box>

                <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
                    <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="caption">Насыщенность</Typography>
                        <Slider
                            value={saturation}
                            onChange={(_, value) => setSaturation(value)}
                            min={0}
                            max={200}
                        />
                    </Box>
                    <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="caption">Размытие</Typography>
                        <Slider
                            value={blur}
                            onChange={(_, value) => setBlur(value)}
                            min={0}
                            max={50}
                        />
                    </Box>
                </Box>

                <Box sx={{ display: 'flex', gap: 2, mb: 2 }}>
                    <Box sx={{ flexGrow: 1 }}>
                        <Typography variant="caption">Прозрачность</Typography>
                        <Slider
                            value={opacity}
                            onChange={(_, value) => setOpacity(value)}
                            min={0}
                            max={100}
                        />
                    </Box>
                </Box>

                <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                    {Object.entries(filters).map(([key, { name }]) => (
                        <Tooltip key={key} title={name}>
                            <IconButton
                                onClick={() => setCurrentFilter(key)}
                                color={currentFilter === key ? 'primary' : 'default'}
                            >
                                <FilterIcon />
                            </IconButton>
                        </Tooltip>
                    ))}
                </Box>
            </DialogContent>
            <DialogActions>
                <Button onClick={onClose}>Отмена</Button>
                <Button
                    onClick={handleSave}
                    variant="contained"
                    startIcon={isProcessing ? <CircularProgress size={20} /> : <SaveIcon />}
                    disabled={isProcessing}
                >
                    Сохранить
                </Button>
            </DialogActions>
        </Dialog>
    );
};

export default ImageEditor;
